    final zNewX = zx * zx - zy * zy + cx;
    final zNewY = 2.0 * zx * zy + cy;
    cx = 0.5 * cx + zNewX;
    cy = 0.5 * cy + zNewY;
    zx = zNewX;
    zy = zNewY;
