/// Renders one CPU RGBA tile from an explicit full-viewport rectangle.
///
/// This pure raster helper is shared by direct, full-frame isolate, and tile
/// isolate render paths so they fail on the same invalid dimensions and sample
/// the same viewport coordinates.
Uint8List renderCpuRectRgba({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  CpuRenderRect(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
  ).validate();

  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'dart:math' as math;

/// Replayable CPU render dimensions for preview/refine/slow-mode passes.
///
/// The CPU renderer uses reduced preview passes while gestures are active and a
/// high-resolution slow-mode pass after refinement. Keeping those dimensions in
/// a pure value object exposes the magic floors/caps and makes tiny viewport
/// edge cases testable without spinning up timers or isolates.
final class CpuRenderResolution {
  const CpuRenderResolution({required this.width, required this.height});

  static const int minInteractiveDimension = 200;
  static const int minSlowModeWidth = 400;
  static const int minSlowModeHeight = 400;
  static const int maxSlowModeWidth = 2160;
  static const int maxSlowModeHeight = 3840;

  final int width;
  final int height;

  factory CpuRenderResolution.forPass({
    required int targetWidth,
    required int targetHeight,
    required double resolutionScale,
  }) {
    return CpuRenderResolution(
      width: _interactiveDimension(
        targetDimension: targetWidth,
        resolutionScale: resolutionScale,
      ),
      height: _interactiveDimension(
        targetDimension: targetHeight,
        resolutionScale: resolutionScale,
      ),
    );
  }

  factory CpuRenderResolution.forSlowMode({
    required int targetWidth,
    required int targetHeight,
  }) {
    return CpuRenderResolution(
      width:
          (targetWidth * 2).clamp(minSlowModeWidth, maxSlowModeWidth).toInt(),
      height: (targetHeight * 2)
          .clamp(minSlowModeHeight, maxSlowModeHeight)
          .toInt(),
    );
  }

  static int _interactiveDimension({
    required int targetDimension,
    required double resolutionScale,
  }) {
    if (!resolutionScale.isFinite || resolutionScale >= 1.0) {
      return targetDimension;
    }
    if (targetDimension <= 0) return targetDimension;

    final lowerBound = math.min(minInteractiveDimension, targetDimension);
    return (targetDimension * resolutionScale)
        .round()
        .clamp(lowerBound, targetDimension)
        .toInt();
  }
}

import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;
  final Set<ReceivePort> _pendingReplies = <ReceivePort>{};
  bool _disposed = false;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    if (_disposed) throw _disposedError();

    final rp = ReceivePort();
    _pendingReplies.add(rp);
    _sendPort.send((req, rp.sendPort));
    try {
      final msg = await rp.first;
      if (msg is CpuTileRenderResponse) return msg;
      if (msg is _CpuTileRenderFailure) throw msg.toException();
      throw StateError('Unexpected CPU tile worker reply: ${msg.runtimeType}');
    } on StateError {
      if (_disposed) throw _disposedError();
      rethrow;
    } finally {
      _pendingReplies.remove(rp);
      rp.close();
    }
  }

  void dispose() {
    if (_disposed) return;
    _disposed = true;
    for (final replyPort in _pendingReplies.toList()) {
      replyPort.close();
    }
    _pendingReplies.clear();
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }

  StateError _disposedError() => StateError('CpuTileWorker has been disposed');
}

/// Exception surfaced when the worker isolate could not render a requested tile.
class CpuTileWorkerException implements Exception {
  const CpuTileWorkerException({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  @override
  String toString() => 'CpuTileWorkerException($errorType): $message';
}

final class _CpuTileRenderFailure {
  const _CpuTileRenderFailure({
    required this.errorType,
    required this.message,
    required this.stackTraceText,
  });

  final String errorType;
  final String message;
  final String stackTraceText;

  factory _CpuTileRenderFailure.from(Object error, StackTrace stackTrace) {
    return _CpuTileRenderFailure(
      errorType: error.runtimeType.toString(),
      message: error.toString(),
      stackTraceText: stackTrace.toString(),
    );
  }

  CpuTileWorkerException toException() {
    return CpuTileWorkerException(
      errorType: errorType,
      message: message,
      stackTraceText: stackTraceText,
    );
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    SendPort? replyTo;
    try {
      final (CpuTileRenderRequest req, SendPort port) =
          msg as (CpuTileRenderRequest, SendPort);
      replyTo = port;
      final resp = renderCpuTileInIsolate(req);
      replyTo.send(resp);
    } catch (error, stackTrace) {
      replyTo?.send(_CpuTileRenderFailure.from(error, stackTrace));
    }
  });
}

import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

